25	// FinalizeDurableAttemptAudit appends the per-attempt metrics row, when the
26	// report carries an attempt_id, and commits any DDx-managed durable audit files
27	// that changed during the attempt.
28	func FinalizeDurableAttemptAudit(projectRoot string, store durableAuditBeadReader, report ExecuteBeadReport) error {
29		if strings.TrimSpace(projectRoot) == "" {
30			projectRoot = report.ProjectRoot
31		}
32		if strings.TrimSpace(projectRoot) == "" {
33			return fmt.Errorf("finalize durable audit: project root required")
34		}
35		if strings.TrimSpace(report.AttemptID) != "" {
36			if err := attemptmetrics.AppendRow(projectRoot, buildAttemptMetricsRow(store, report, time.Now().UTC())); err != nil {
37				return fmt.Errorf("append attempt metrics: %w", err)
38			}
39		}
40		if err := CommitDurableAuditOutputs(projectRoot, report.AttemptID); err != nil {
41			return fmt.Errorf("commit durable audit outputs: %w", err)
42		}
43		return nil
44	}
