55	func buildAttemptMetricsRow(store durableAuditBeadReader, report ExecuteBeadReport, finishedAt time.Time) attemptmetrics.AttemptRow {
56		specID := ""
57		if report.BeadID != "" && store != nil {
58			if b, err := store.Get(context.Background(), report.BeadID); err == nil && b != nil {
59				specID, _ = b.Extra["spec-id"].(string)
60			}
61		}
62		tsEnd := attemptmetrics.Rfc3339(finishedAt)
63		tsStart := ""
64		if report.DurationMS > 0 {
65			start := finishedAt.Add(-time.Duration(report.DurationMS) * time.Millisecond)
66			tsStart = attemptmetrics.Rfc3339(start)
67		}
68		return attemptmetrics.AttemptRow{
69			SchemaVersion: attemptmetrics.SchemaVersion,
70			AttemptID:     report.AttemptID,
71			BeadID:        report.BeadID,
72			SessionID:     report.SessionID,
73			TSStart:       tsStart,
74			TSEnd:         tsEnd,
75			Model:         report.Model,
76			Harness:       report.Harness,
77			Profile:       report.RequestedProfile,
78			Provider:      report.Provider,
79			SpecID:        specID,
80			Outcome:       report.Status,
