132	func dirtyDurableAuditPaths(statusOutput string) []string {
133		lines := strings.Split(statusOutput, "\n")
134		seen := make(map[string]struct{}, len(lines))
135		paths := make([]string, 0, len(lines))
136		for _, line := range lines {
137			if len(line) < 4 {
138				continue
139			}
140			path := strings.TrimSpace(line[3:])
141			if arrow := strings.LastIndex(path, " -> "); arrow >= 0 {
142				path = strings.TrimSpace(path[arrow+4:])
143			}
144			if path == "" {
145				continue
146			}
147			if _, ok := seen[path]; ok {
148				continue
149			}
150			seen[path] = struct{}{}
151			paths = append(paths, path)
152		}
153		return paths
154	}
