package agent

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/attemptmetrics"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

type mockReviewerForVerdict struct {
	verdict string
}

func (m *mockReviewerForVerdict) ReviewBead(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
	if m.verdict == "APPROVE" {
		return &ReviewResult{
			ReviewerIndex:  0,
			Verdict:        VerdictApprove,
			Rationale:      "All ACs satisfied with evidence",
			RawOutput:      "reviewer output",
			ReviewerHarness: "test-harness",
			ReviewerModel:   "test-model",
			InputBytes:     100,
			OutputBytes:    50,
			DurationMS:     1000,
			PerAC: []ReviewAC{
				{Number: 1, Item: "AC1", Grade: "pass", Evidence: "Evidence for AC1"},
				{Number: 2, Item: "AC2", Grade: "pass", Evidence: "Evidence for AC2"},
			},
		}, nil
	}
	if m.verdict == "REQUEST_CHANGES" {
		return &ReviewResult{
			ReviewerIndex:   0,
			Verdict:         VerdictRequestChanges,
			Rationale:       "AC2 needs more work",
			RawOutput:       "reviewer output",
			ReviewerHarness: "test-harness",
			ReviewerModel:   "test-model",
			InputBytes:      100,
			OutputTokens:    50,
			DurationMS:      1000,
			PerAC: []ReviewAC{
				{Number: 1, Item: "AC1", Grade: "pass", Evidence: "Evidence for AC1"},
				{Number: 2, Item: "AC2", Grade: "fail", Evidence: "AC2 incomplete"},
			},
		}, nil
	}
	return nil, nil
}

type mockStoreForVerdict struct {
	events map[string][]bead.BeadEvent
}

func (m *mockStoreForVerdict) CloseWithEvidence(beadID, sessionID, resultRev string) error {
	return nil
}

func (m *mockStoreForVerdict) AppendEvent(beadID string, event bead.BeadEvent) error {
	if m.events == nil {
		m.events = make(map[string][]bead.BeadEvent)
	}
	m.events[beadID] = append(m.events[beadID], event)
	return nil
}

func (m *mockStoreForVerdict) Events(beadID string) ([]bead.BeadEvent, error) {
