func TestRunPostMergeReview_APPROVEVerdictInReport(t *testing.T) {
	store := &mockStoreForVerdict{}
	reviewer := &mockReviewerForVerdict{verdict: "APPROVE"}

	input := PostMergeReviewInput{
		Bead: bead.Bead{
			ID:     "test-bead-approve",
			Labels: []string{},
		},
		Report: ExecuteBeadReport{
			BeadID:      "test-bead-approve",
			AttemptID:   "attempt-approve-001",
			SessionID:   "session-001",
			Status:      ExecuteBeadStatusSuccess,
			ResultRev:   "abc123",
			BaseRev:     "base123",
			ProjectRoot: t.TempDir(),
		},
		Reviewer:    reviewer,
		Store:       store,
		ProjectRoot: t.TempDir(),
		Rcfg:        config.NewTestConfig(),
		NoReview:    false,
		Assignee:    "test-agent",
		Now:         time.Now,
	}

	output := RunPostMergeReview(context.Background(), input)

	// Verify the report has the verdict
	assert.Equal(t, "APPROVE", output.Report.ReviewVerdict)
	assert.Equal(t, "All ACs satisfied with evidence", output.Report.ReviewRationale)
	assert.True(t, output.Approved)

	// Verify the bead event was recorded with the verdict
	events := store.events["test-bead-approve"]
	require.Greater(t, len(events), 0)
	reviewEvent := events[len(events)-1]
	assert.Equal(t, "review", reviewEvent.Kind)
	assert.Equal(t, "APPROVE", reviewEvent.Summary)
}

func TestRunPostMergeReview_REQUESTCHANGESVerdictInReport(t *testing.T) {
	store := &mockStoreForVerdict{}
	reviewer := &mockReviewerForVerdict{verdict: "REQUEST_CHANGES"}

	input := PostMergeReviewInput{
		Bead: bead.Bead{
			ID:     "test-bead-changes",
			Labels: []string{},
		},
		Report: ExecuteBeadReport{
			BeadID:      "test-bead-changes",
			AttemptID:   "attempt-changes-001",
			SessionID:   "session-001",
			Status:      ExecuteBeadStatusSuccess,
			ResultRev:   "def456",
			BaseRev:     "base123",
			ProjectRoot: t.TempDir(),
		},
		Reviewer:    reviewer,
		Store:       store,
		ProjectRoot: t.TempDir(),
		Rcfg:        config.NewTestConfig(),
		NoReview:    false,
		Assignee:    "test-agent",
		Now:         time.Now,
	}

	output := RunPostMergeReview(context.Background(), input)

	// Verify the report has the verdict
	assert.Equal(t, "REQUEST_CHANGES", output.Report.ReviewVerdict)
	assert.Equal(t, "AC2 needs more work", output.Report.ReviewRationale)
	assert.False(t, output.Approved)

	// Verify the bead event was recorded with the verdict
	events := store.events["test-bead-changes"]
	require.Greater(t, len(events), 0)
	reviewEvent := events[len(events)-1]
	assert.Equal(t, "review", reviewEvent.Kind)
	assert.Equal(t, "REQUEST_CHANGES", reviewEvent.Summary)
}

func TestPostMergeReview_VerdictPersistsToMetrics(t *testing.T) {
	projectRoot := t.TempDir()
	store := &mockStoreForVerdict{}
	reviewer := &mockReviewerForVerdict{verdict: "APPROVE"}

	// Run post-merge review with APPROVE verdict
	input := PostMergeReviewInput{
		Bead: bead.Bead{
			ID:     "test-bead-metrics",
			Labels: []string{},
			Extra:  map[string]any{"spec-id": "SPEC-456"},
		},
		Report: ExecuteBeadReport{
			BeadID:           "test-bead-metrics",
			AttemptID:        "attempt-metrics-001",
			SessionID:        "session-001",
			Status:           ExecuteBeadStatusSuccess,
			ResultRev:        "ghi789",
			BaseRev:          "base123",
			ProjectRoot:      projectRoot,
			Model:            "test-model",
			Provider:         "test-provider",
			Harness:          "test-harness",
			CostUSD:          0.42,
			DurationMS:       5000,
			RequestedProfile: "standard",
		},
		Reviewer:    reviewer,
		Store:       store,
		ProjectRoot: projectRoot,
		Rcfg:        config.NewTestConfig(),
		NoReview:    false,
		Assignee:    "test-agent",
		Now:         time.Now,
	}

	output := RunPostMergeReview(context.Background(), input)

	// Build the attempt metrics row as would happen in FinalizeDurableAttemptAudit
	row := attemptmetrics.AttemptRow{
		SchemaVersion: attemptmetrics.SchemaVersion,
		AttemptID:     output.Report.AttemptID,
		BeadID:        output.Report.BeadID,
		SessionID:     output.Report.SessionID,
		Model:         output.Report.Model,
		Provider:      output.Report.Provider,
		Harness:       output.Report.Harness,
		SpecID:        "SPEC-456",
		Outcome:       output.Report.Status,
		CostUSD:       output.Report.CostUSD,
		DurationMS:    int(output.Report.DurationMS),
		ReviewVerdict: output.Report.ReviewVerdict,
	}

	// Write the row to the metrics file
	err := attemptmetrics.AppendRow(projectRoot, row)
	require.NoError(t, err)

	// Read back the metrics rows
	rows, err := attemptmetrics.LoadRows(projectRoot)
	require.NoError(t, err)
	require.Len(t, rows, 1)

	// Verify the verdict is in the metrics
	assert.Equal(t, "APPROVE", rows[0].ReviewVerdict)
	assert.Equal(t, "test-bead-metrics", rows[0].BeadID)
	assert.Equal(t, "SPEC-456", rows[0].SpecID)

	// Verify the metrics file exists and contains valid JSON
	metricsPath := attemptmetrics.AttemptsPath(projectRoot)
	data, err := os.ReadFile(metricsPath)
	require.NoError(t, err)
	lines := string(data)
	require.NotEmpty(t, lines)

	// Verify the JSON is parseable
	var parsedRow attemptmetrics.AttemptRow
	err = json.Unmarshal([]byte(lines), &parsedRow)
	require.NoError(t, err)
	assert.Equal(t, "APPROVE", parsedRow.ReviewVerdict)
}

func TestPostMergeReview_AllVerdictPathsPreserveReport(t *testing.T) {
	verdicts := []struct {
		name    string
		verdict string
	}{
		{"APPROVE", "APPROVE"},
		{"REQUEST_CHANGES", "REQUEST_CHANGES"},
	}

	for _, tc := range verdicts {
		t.Run(tc.name, func(t *testing.T) {
			projectRoot := t.TempDir()
			store := &mockStoreForVerdict{}
			reviewer := &mockReviewerForVerdict{verdict: tc.verdict}

			input := PostMergeReviewInput{
				Bead: bead.Bead{
					ID:     "test-bead-" + tc.name,
					Labels: []string{},
					Extra:  map[string]any{"spec-id": "SPEC-" + tc.name},
				},
				Report: ExecuteBeadReport{
					BeadID:           "test-bead-" + tc.name,
					AttemptID:        "attempt-" + tc.name,
					SessionID:        "session-001",
					Status:           ExecuteBeadStatusSuccess,
					ResultRev:        "rev-" + tc.name,
					BaseRev:          "base123",
					ProjectRoot:      projectRoot,
					Model:            "test-model",
					Provider:         "test-provider",
					Harness:          "test-harness",
					CostUSD:          0.42,
					DurationMS:       5000,
					RequestedProfile: "standard",
				},
				Reviewer:    reviewer,
				Store:       store,
				ProjectRoot: projectRoot,
				Rcfg:        config.NewTestConfig(),
				NoReview:    false,
				Assignee:    "test-agent",
				Now:         time.Now,
			}

			output := RunPostMergeReview(context.Background(), input)

			// Verify report is returned with verdict
			require.NotNil(t, output.Report)
			assert.NotEmpty(t, output.Report.ReviewVerdict, "verdict should be set for %s", tc.name)
			assert.NotEmpty(t, output.Report.ReviewRationale, "rationale should be set for %s", tc.name)

			// Verify the verdict matches what was returned
			assert.Equal(t, tc.verdict, output.Report.ReviewVerdict)

			// Write to metrics and verify round-trip
			row := attemptmetrics.AttemptRow{
				SchemaVersion: attemptmetrics.SchemaVersion,
				AttemptID:     output.Report.AttemptID,
				BeadID:        output.Report.BeadID,
				ReviewVerdict: output.Report.ReviewVerdict,
			}
			err := attemptmetrics.AppendRow(projectRoot, row)
			require.NoError(t, err)

			rows, err := attemptmetrics.LoadRows(projectRoot)
			require.NoError(t, err)
			require.Len(t, rows, 1)
			assert.Equal(t, tc.verdict, rows[0].ReviewVerdict)
		})
	}
}

